class Solution:
    def constructProductMatrix(self, grid: List[List[int]]) -> List[List[int]]:
        n, m = len(grid), len(grid[0])
        product = [[0] * m for _ in range(n)]
        total_product = 1

        # Compute the product of all elements
        for i in range(n):
            for j in range(m):
                total_product = (total_product * grid[i][j]) % 12345

        # Compute the product matrix
        for i in range(n):
            for j in range(m):
                product[i][j] = (total_product * pow(grid[i][j], 12345 - 2, 12345)) % 12345

        return product
